import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoMarqueeItems = [
  { id: "v1", src: "/assets/videos/cooking.mp4", alt: "Cooking", type: "video" },
  { id: "v2", src: "/assets/videos/vid2.mp4", alt: "Vid 2", type: "video" },
  { id: "v3", src: "/assets/videos/vid3.mp4", alt: "Vid 3", type: "video" },
  { id: "v4", src: "/assets/videos/vid5.mp4", alt: "Vid 5", type: "video" },
  { id: "v5", src: "/assets/videos/vid6.mp4", alt: "Vid 6", type: "video" }
];

const placeholderImages = [
  { id: "i1", src: "/assets/amb.jpg", alt: "Ambience" },
  { id: "i2", src: "/assets/apr.jpg", alt: "Aperitif" },
  { id: "i3", src: "/assets/ballent.jpg", alt: "Ballentine" },
  { id: "i4", src: "/assets/bl.jpg", alt: "Bar Lounge" },
  { id: "i5", src: "/assets/bn.jpg", alt: "Bar Night" },
  { id: "i6", src: "/assets/dj.jpg", alt: "DJ Night" },
  { id: "i7", src: "/assets/dri.jpg", alt: "Drinks" },
  { id: "i8", src: "/assets/f1.jpg", alt: "Food" },
  { id: "i9", src: "/assets/grp.jpg", alt: "Group" },
  { id: "i10", src: "/assets/nod.jpg", alt: "Night Out" },
  { id: "i11", src: "/assets/pic.jpg", alt: "Vibes" },
  { id: "i12", src: "/assets/piz.jpg", alt: "Pizza" }
];

const MovingGallery = () => {
  const renderItem = (item) => {
    if (item.type === "video") {
      return (
        <video
          key={item.id}
          preload="metadata"
          src={item.src}
          className="w-[210px] md:w-[260px] h-[350px] md:h-[440px] object-cover rounded-2xl shadow-2xl bg-black inline-block [margin-right:0]"
          muted
          autoPlay
          loop
          playsInline
        />
      );
    }
    return (
      <motion.img
        key={item.id}
        src={item.src}
        alt={item.alt}
        className="w-[290px] md:w-[370px] h-[180px] md:h-[240px] object-cover rounded-xl inline-block grayscale hover:grayscale-0 hover:scale-105 shadow-lg [margin-right:0]"
        initial={{ opacity: 0.9 }}
        whileHover={{ scale: 1.02 }}
        loading="lazy"
      />
    );
  };

  return (
    <section className="py-20 bg-black overflow-hidden">
      <div className="text-center mb-20">
        <span className="inline-block font-accent text-gold text-sm tracking-[0.3em] uppercase mb-6 px-4 py-2">
          Experience The Vibe
        </span>
        <h2 className="font-heading text-5xl md:text-6xl lg:text-7xl text-white leading-none">
          Corridor in Motion
        </h2>
      </div>

      {/* Video Marquee - Seamless */}
      <Marquee speed={25} gradient={false} pauseOnHover className="mb-16" style={{ gap: '0px' }}>
        {videoMarqueeItems.map(renderItem)}
      </Marquee>

      {/* Images LTR */}
      <Marquee speed={45} gradient={false} pauseOnHover className="mb-16" style={{ gap: '0px' }}>
        {placeholderImages.slice(0, 9).map(renderItem)}
      </Marquee>

      {/* Images RTL */}
      <Marquee speed={45} direction="right" gradient={false} pauseOnHover style={{ gap: '0px' }}>
        {placeholderImages.slice(0, 6).map(renderItem)}
      </Marquee>
    </section>
  );
};

export default MovingGallery;
